5614     //     s1 = phi [s.init, scalar.ph], [s2, scalar.body]
5615     //     s2 = a[i]
5616     //     b[i] = s2 - s1
5617     //     br cond, scalar.body, exit.block
5618     //
5619     //   exit.block:
5620     //     use = lcssa.phi [s1, scalar.body]
