5640     //   middle.block:
5641     //     vector.recur.extract.for.phi = v2(2)
5642     //     vector.recur.extract = v2(3)
5643     //     br cond, scalar.ph, exit.block
5644     //
5645     //   scalar.ph:
5646     //     scalar.recur.init = phi [vector.recur.extract, middle.block],
