2534 void VPScalarIVStepsRecipe::execute(VPTransformState &State) {
2535   // Fast-math-flags propagate from the original induction instruction.
2536   IRBuilder<>::FastMathFlagGuard FMFG(State.Builder);
2537   State.Builder.setFastMathFlags(getFastMathFlags());
2538 
2539   /// Compute scalar induction steps. \p ScalarIV is the scalar induction
2540   /// variable on which to base the steps, \p Step is the size of the step.
2541 
2542   Value *BaseIV = State.get(getOperand(0), VPLane(0));
2543   Value *Step = State.get(getStepValue(), VPLane(0));
2544   IRBuilderBase &Builder = State.Builder;
2545 
2546   // Ensure step has the same type as that of scalar IV.
2547   Type *BaseIVTy = BaseIV->getType()->getScalarType();
2548   assert(BaseIVTy == Step->getType() && "Types of BaseIV and Step must match!");
2549 
2550   // We build scalar steps for both integer and floating-point induction
2551   // variables. Here, we determine the kind of arithmetic we will perform.
2552   Instruction::BinaryOps AddOp;
2553   Instruction::BinaryOps MulOp;
2554   if (BaseIVTy->isIntegerTy()) {
2555     AddOp = Instruction::Add;
2556     MulOp = Instruction::Mul;
2557   } else {
2558     AddOp = InductionOpcode;
2559     MulOp = Instruction::FMul;
2560   }
2561 
2562   // Determine the number of scalars we need to generate.
2563   bool FirstLaneOnly = vputils::onlyFirstLaneUsed(this);
2564   // Compute the scalar steps and save the results in State.
2565 
2566   unsigned StartLane = 0;
2567   unsigned EndLane = FirstLaneOnly ? 1 : State.VF.getKnownMinValue();
2568   if (State.Lane) {
2569     StartLane = State.Lane->getKnownLane();
2570     EndLane = StartLane + 1;
2571   }
2572   Value *StartIdx0 = getStartIndex() ? State.get(getStartIndex(), true)
2573                                      : Constant::getNullValue(BaseIVTy);
2574 
2575   for (unsigned Lane = StartLane; Lane < EndLane; ++Lane) {
2576     // It is okay if the induction variable type cannot hold the lane number,
2577     // we expect truncation in this case.
2578     Constant *LaneValue =
2579         BaseIVTy->isIntegerTy()
2580             ? ConstantInt::get(BaseIVTy, Lane, /*IsSigned=*/false,
2581                                /*ImplicitTrunc=*/true)
2582             : ConstantFP::get(BaseIVTy, Lane);
2583     Value *StartIdx = Builder.CreateBinOp(AddOp, StartIdx0, LaneValue);
2584     // The step returned by `createStepForVF` is a runtime-evaluated value
2585     // when VF is scalable. Otherwise, it should be folded into a Constant.
2586     assert((State.VF.isScalable() || isa<Constant>(StartIdx)) &&
2587            "Expected StartIdx to be folded to a constant when VF is not "
2588            "scalable");
2589     auto *Mul = Builder.CreateBinOp(MulOp, StartIdx, Step);
2590     auto *Add = Builder.CreateBinOp(AddOp, BaseIV, Mul);
2591     State.set(this, Add, VPLane(Lane));
2592   }
2593 }
