2623     // the GEP we build (by only using vector-typed operands for
2624     // loop-varying values) would be a scalar pointer. Thus, to ensure we
2625     // produce a vector of pointers, we need to either arbitrarily pick an
2626     // operand to broadcast, or broadcast a clone of the original GEP.
2627     // Here, we broadcast a clone of the original.
2628 
2629     SmallVector<Value *> Ops;
2630     for (unsigned I = 0, E = getNumOperands(); I != E; I++)
2631       Ops.push_back(State.get(getOperand(I), VPLane(0)));
